The `TabBar` component provides a UI element for managing multiple tabs within the application. It allows users to switch between tabs, close them, and open new ones.

**Key Exports/Functions/Props:**

*   `TabBar` function:
    *   `tabs`: An array of `Tab` objects, where each `Tab` has an `id` and a `label`. (Type: `Tab[]`)
    *   `activeTabId`: The ID of the currently active tab. (Type: `string`)
    *   `onSwitch`: A callback function invoked when a tab is clicked to switch to it. It receives the `id` of the clicked tab. (Type: `(id: string) => void`)
    *   `onClose`: A callback function invoked when a tab's close button is clicked or when the middle mouse button is used on a tab. It receives the `id` of the tab to be closed. (Type: `(id: string) => void`)
    *   `onAdd`: A callback function invoked when the "New tab" button is clicked. (Type: `() => void`)

**Usage Example:**

```jsx
import React, { useState } from 'react';
import { TabBar } from './TabBar';
import type { Tab } from './types';

function App() {
  const [tabs, setTabs] = useState<Tab[]>([{ id: '1', label: 'Tab 1' }]);
  const [activeTabId, setActiveTabId] = useState<string>('1');
  const [nextId, setNextId] = useState(2);

  const handleSwitchTab = (id: string) => {
    setActiveTabId(id);
  };

  const handleCloseTab = (id: string) => {
    const newTabs = tabs.filter(tab => tab.id !== id);
    setTabs(newTabs);
    // If the closed tab was active, switch to the first remaining tab or do nothing if no tabs left
    if (activeTabId === id && newTabs.length > 0) {
      setActiveTabId(newTabs[0].id);
    } else if (newTabs.length === 0) {
      // Handle case where all tabs are closed
      setActiveTabId('');
    }
  };

  const handleAddTab = () => {
    const newTabId = String(nextId);
    setTabs([...tabs, { id: newTabId, label: `Tab ${nextId}` }]);
    setActiveTabId(newTabId);
    setNextId(nextId + 1);
  };

  return (
    <div>
      <TabBar
        tabs={tabs}
        activeTabId={activeTabId}
        onSwitch={handleSwitchTab}
        onClose={handleCloseTab}
        onAdd={handleAddTab}
      />
      {/* Content for the active tab would go here */}
      <div>
        Currently active tab: {tabs.find(tab => tab.id === activeTabId)?.label || 'None'}
      </div>
    </div>
  );
}

export default App;
```
